#!/usr/bin/env python3
import os,sys,json,glob,time,base64,subprocess,re,urllib.request
# 1) find which env files the brain/publish units load, and load them (strip export) to get STATUS_TOKEN
cat=subprocess.run(["bash","-lc","systemctl cat brain-improve-hourly.service atlas-improve-publish.service 2>/dev/null"],capture_output=True,text=True).stdout
envfiles=re.findall(r'EnvironmentFile=-?(\S+)', cat)
for f in envfiles+["/etc/atlas/autopull.env","/etc/atlas/status.env","/etc/atlas/db.env","/etc/atlas/brain.env"]:
    if os.path.exists(f):
        for ln in open(f):
            ln=ln.strip()
            if ln.startswith("export "): ln=ln[7:]
            if "=" in ln and not ln.startswith("#"):
                k,v=ln.split("=",1)
                if k.strip() not in os.environ: os.environ[k.strip()]=v.strip().strip('"').strip("'")
out={"kind":"brain-diag2","ts":int(time.time()),"envfiles":envfiles,
     "have_token":bool(os.environ.get("STATUS_TOKEN")),"have_repo":bool(os.environ.get("STATUS_REPO"))}
# 2) read the ACTUAL latest improvement report to see why idea_count=0
cands=glob.glob("/var/lib/atlas/**/improvement-report-latest.json",recursive=True)+["/var/lib/atlas/status/improvement-report-latest.json"]
rpt=next((c for c in cands if os.path.exists(c)),None)
out["report_path"]=rpt
if rpt:
    r=json.load(open(rpt))
    out["report_keys"]=list(r.keys())
    out["ideas_len"]=len(r.get("ideas") or r.get("ranked_ideas") or [])
    out["pass"]=r.get("pass") or r.get("pass_kind")
    out["report_sample"]=json.dumps(r)[:1800]
else:
    out["found"]=glob.glob("/var/lib/atlas/**/improve*report*.json",recursive=True)[:8]
# 3) what generates it + last error
out["journal"]=subprocess.run(["bash","-lc","journalctl -u brain-improve-hourly.service --no-pager -n 20 2>/dev/null | tail -20"],capture_output=True,text=True).stdout[-1800:]
# publish
tok=os.environ.get("STATUS_TOKEN");repo=os.environ.get("STATUS_REPO")
if tok and repo:
    url="https://api.github.com/repos/%s/contents/status/hetzner/brain-diag2.json"%repo
    body={"message":"brain-diag2","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
    try:
        rr=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Accept":"application/vnd.github+json"})
        body["sha"]=json.load(urllib.request.urlopen(rr,timeout=20)).get("sha")
    except Exception: pass
    try:
        rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Content-Type":"application/json","Accept":"application/vnd.github+json"})
        urllib.request.urlopen(rq,timeout=25); print("brain-diag2 published")
    except Exception as e: print("pub_err",str(e)[:120])
else:
    print("STILL no token; envfiles=",envfiles)
